import warnings
import functools

def deprecated(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        warnings.warn(
            f"Call to deprecated function {func.__name__}.",
            category=DeprecationWarning,
            stacklevel=2
        )
        return func(*args, **kwargs)
    return wrapper

if __name__ == '__main__':
    @deprecated
    def old_function(a, b):
        return a + b

    @deprecated
    def another_old_function():
        print("This is an old function being called.")

    print("Calling old_function:")
    result = old_function(5, 3)
    print(f"Result: {result}")

    print("\nCalling another_old_function:")
    another_old_function()

    def new_function(x):
        return x * 2

    print("\nCalling new_function (not deprecated):")
    print(f"Result: {new_function(10)}")
